package com.cora.stylefinder.member.config;
import com.cora.stylefinder.member.common.RequestIdFilter; import org.springframework.beans.factory.annotation.Value; import org.springframework.context.annotation.*; import org.springframework.security.config.annotation.web.builders.HttpSecurity; import org.springframework.security.config.http.SessionCreationPolicy; import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.security.web.SecurityFilterChain; import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter; import org.springframework.web.cors.*; import java.util.*;
@Configuration public class SecurityConfig { @Bean PasswordEncoder passwordEncoder(){return new BCryptPasswordEncoder();} @Bean SecurityFilterChain security(HttpSecurity h,JwtAuthenticationFilter jwt,RequestIdFilter requestId)throws Exception{return h.csrf(c->c.disable()).cors(c->{}).sessionManagement(s->s.sessionCreationPolicy(SessionCreationPolicy.STATELESS)).authorizeHttpRequests(a->a.requestMatchers("/health/**","/api/members/signup","/api/members/login","/api/members/token/refresh").permitAll().anyRequest().authenticated()).addFilterBefore(requestId,UsernamePasswordAuthenticationFilter.class).addFilterAfter(jwt,RequestIdFilter.class).build();} @Bean CorsConfigurationSource cors(@Value("${app.cors-origins}") String origins){var c=new CorsConfiguration();c.setAllowedOrigins(Arrays.stream(origins.split(",")).map(String::trim).toList());c.setAllowedMethods(List.of("GET","POST","OPTIONS"));c.setAllowedHeaders(List.of("Authorization","Content-Type","X-Request-ID"));var s=new UrlBasedCorsConfigurationSource();s.registerCorsConfiguration("/**",c);return s;} }
